  function generateRecoveryCodes(): string[] {
    const codes: string[] = [];
    for (let i = 0; i < 8; i++) {
      codes.push(crypto.randomBytes(4).toString("hex").toUpperCase());
    }
    return codes;
  }

  app.post("/api/2fa/setup", async (req: Request, res: Response) => {
    try {
      const userId = req.headers["x-user-id"] as string;
      if (!userId) {
        res.status(401).json({ error: "Authentication required" });
        return;
      }

      const [user] = await db.select().from(users).where(eq(users.id, userId));
      if (!user) {
        res.status(404).json({ error: "User not found" });
        return;
      }

      if (user.totpEnabled) {
        res.status(400).json({ error: "2FA is already enabled" });
        return;
      }

      const secret = new OTPAuth.Secret({ size: 20 });
      const totp = new OTPAuth.TOTP({
        issuer: "Workforce Connect",
        label: user.email,
        algorithm: "SHA1",
        digits: 6,
        period: 30,
        secret,
      });

      await db.update(users)
        .set({ totpSecret: secret.base32, updatedAt: new Date() })
        .where(eq(users.id, userId));

      res.json({
        secret: secret.base32,
        uri: totp.toString(),
      });
    } catch (error) {
      console.error("Error setting up 2FA:", error);
      res.status(500).json({ error: "Failed to setup 2FA" });
    }
  });

  app.post("/api/2fa/verify-setup", async (req: Request, res: Response) => {
    try {
      const userId = req.headers["x-user-id"] as string;
      if (!userId) {
        res.status(401).json({ error: "Authentication required" });
        return;
      }

      const { code } = req.body;
      if (!code) {
        res.status(400).json({ error: "Verification code is required" });
        return;
      }

      const [user] = await db.select().from(users).where(eq(users.id, userId));
      if (!user || !user.totpSecret) {
        res.status(400).json({ error: "2FA setup not initiated" });
        return;
      }

      const totp = new OTPAuth.TOTP({
        issuer: "Workforce Connect",
        label: user.email,
        algorithm: "SHA1",
        digits: 6,
        period: 30,
        secret: OTPAuth.Secret.fromBase32(user.totpSecret),
      });

      const delta = totp.validate({ token: code, window: 1 });
      if (delta === null) {
        res.status(400).json({ error: "Invalid verification code" });
        return;
      }

      const recoveryCodes = generateRecoveryCodes();

      await db.update(users)
        .set({
          totpEnabled: true,
          recoveryCodes: JSON.stringify(recoveryCodes),
          updatedAt: new Date(),
        })
        .where(eq(users.id, userId));

      res.json({
        enabled: true,
        recoveryCodes,
      });
    } catch (error) {
      console.error("Error verifying 2FA setup:", error);
      res.status(500).json({ error: "Failed to verify 2FA setup" });
    }
  });

