import React, { useState, useCallback, useRef } from "react";
import {
  View,
  TextInput,
  StyleSheet,
  Pressable,
  ActivityIndicator,
  ScrollView,
  ViewStyle,
} from "react-native";
import { Feather } from "@expo/vector-icons";
import { ThemedText } from "@/components/ThemedText";
import { useTheme } from "@/hooks/useTheme";
import { BorderRadius, Spacing, Typography } from "@/constants/theme";
import { apiRequest } from "@/lib/query-client";

export interface AddressData {
  formattedAddress: string;
  addressLine1: string;
  city: string;
  province: string;
  postalCode: string;
  country: string;
  latitude: number | null;
  longitude: number | null;
}

interface Prediction {
  place_id: string;
  description: string;
  structured_formatting?: {
    main_text: string;
    secondary_text: string;
  };
}

interface AddressAutocompleteProps {
  label?: string;
  value: string;
  onAddressSelect: (address: AddressData) => void;
  onClear?: () => void;
  error?: string;
  containerStyle?: ViewStyle;
  placeholder?: string;
  userRole: string;
  userId: string;
  isAddressSelected?: boolean;
}

export function AddressAutocomplete({
  label,
  value,
  onAddressSelect,
  onClear,
  error,
  containerStyle,
  placeholder = "Search address...",
  userRole,
  userId,
  isAddressSelected = false,
}: AddressAutocompleteProps) {
  const { theme } = useTheme();
  const [inputValue, setInputValue] = useState(value);
  const [predictions, setPredictions] = useState<Prediction[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [showDropdown, setShowDropdown] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const fetchPredictions = useCallback(async (input: string) => {
    if (input.length < 2) {
      setPredictions([]);
      setShowDropdown(false);
      setApiError(null);
      return;
    }

    setIsLoading(true);
    setApiError(null);
    try {
      const response = await apiRequest("GET", `/api/places/autocomplete?input=${encodeURIComponent(input)}`);
      const data = await response.json();
      setPredictions(data.predictions || []);
      setShowDropdown(data.predictions?.length > 0);
    } catch (err) {
      console.error("Error fetching predictions:", err);
      setApiError("Address search unavailable. Please check your connection.");
    } finally {
      setIsLoading(false);
    }
  }, [userRole, userId]);

  const handleInputChange = (text: string) => {
    setInputValue(text);

    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
    }

    debounceRef.current = setTimeout(() => {
      fetchPredictions(text);
    }, 300);
  };

  const handleSelectPrediction = async (prediction: Prediction) => {
    setIsLoading(true);
    setShowDropdown(false);

    try {
      const response = await apiRequest("GET", `/api/places/details/${prediction.place_id}`);
      const addressData: AddressData = await response.json();
      setInputValue(addressData.formattedAddress);
      onAddressSelect(addressData);
      setPredictions([]);
    } catch (err) {
      console.error("Error fetching address details:", err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleClear = () => {
    setInputValue("");
    setPredictions([]);
    setShowDropdown(false);
    onClear?.();
  };

  return (
    <View style={[styles.container, containerStyle]}>
      {label ? (
        <ThemedText style={[styles.label, { color: theme.textSecondary }]}>
          {label}
        </ThemedText>
      ) : null}

      <View style={styles.inputWrapper}>
        <View style={[
          styles.inputContainer,
          {
            backgroundColor: theme.backgroundDefault,
            borderColor: error ? theme.error : isAddressSelected ? theme.success : theme.border,
            borderWidth: isAddressSelected ? 2 : 1,
          },
        ]}>
          <Feather 
            name="search" 
            size={18} 
            color={theme.textMuted} 
            style={styles.searchIcon}
          />
          <TextInput
            style={[styles.input, { color: theme.text }]}
            value={inputValue}
            onChangeText={handleInputChange}
            placeholder={placeholder}
            placeholderTextColor={theme.textMuted}
            onFocus={() => {
              if (predictions.length > 0) {
                setShowDropdown(true);
              }
            }}
          />
          {isLoading ? (
            <ActivityIndicator size="small" color={theme.primary} style={styles.clearButton} />
          ) : inputValue.length > 0 ? (
            <Pressable onPress={handleClear} style={styles.clearButton}>
              <Feather name="x" size={18} color={theme.textMuted} />
            </Pressable>
          ) : null}
        </View>

        {showDropdown && predictions.length > 0 ? (
          <View style={[
            styles.dropdown,
            {
              backgroundColor: theme.backgroundDefault,
              borderColor: theme.border,
            },
          ]}>
            <ScrollView 
              style={styles.dropdownScroll}
              keyboardShouldPersistTaps="handled"
              nestedScrollEnabled
            >
              {predictions.map((prediction) => (
                <Pressable
                  key={prediction.place_id}
                  style={({ pressed }) => [
                    styles.predictionItem,
                    { 
                      backgroundColor: pressed ? theme.backgroundElevated : theme.backgroundDefault,
                    },
                  ]}
                  onPress={() => handleSelectPrediction(prediction)}
                >
                  <Feather 
                    name="map-pin" 
                    size={16} 
                    color={theme.textSecondary} 
                    style={styles.predictionIcon}
                  />
                  <View style={styles.predictionTextContainer}>
                    <ThemedText style={styles.predictionMain} numberOfLines={1}>
                      {prediction.structured_formatting?.main_text || prediction.description.split(",")[0]}
                    </ThemedText>
                    <ThemedText style={[styles.predictionSecondary, { color: theme.textSecondary }]} numberOfLines={1}>
                      {prediction.structured_formatting?.secondary_text || prediction.description}
                    </ThemedText>
                  </View>
                </Pressable>
              ))}
            </ScrollView>
          </View>
        ) : null}
      </View>

      {apiError ? (
        <View style={styles.apiErrorContainer}>
          <Feather name="alert-circle" size={14} color={theme.warning} />
          <ThemedText style={[styles.apiErrorText, { color: theme.warning }]}>
            {apiError}
          </ThemedText>
        </View>
      ) : null}

      {isAddressSelected ? (
        <View style={styles.selectedIndicator}>
          <Feather name="check-circle" size={14} color={theme.success} />
          <ThemedText style={[styles.selectedText, { color: theme.success }]}>
            Address selected with GPS coordinates
          </ThemedText>
        </View>
      ) : null}

