                  <Feather name="user" size={size} color={color} />
                ),
              }}
            />
          </>
        );

      case "admin":
        return (
          <>
            <Tab.Screen
              name="Dashboard"
              component={DashboardScreen}
              options={{
                headerTitle: () => <HeaderTitle title="Workforce Connect" />,
                tabBarIcon: ({ color, size }) => (
                  <Feather name="home" size={size} color={color} />
                ),
              }}
            />
            <Tab.Screen
              name="ShiftRequests"
              component={ShiftRequestsScreen}
              options={{
                title: "Requests",
                headerTitle: "Shift Requests",
                tabBarIcon: ({ color, size }) => (
                  <Feather name="send" size={size} color={color} />
                ),
              }}
            />
            <Tab.Screen
              name="Management"
              component={AdminManageScreen}
              options={{
                headerTitle: "Management",
                tabBarIcon: ({ color, size }) => (
                  <Feather name="briefcase" size={size} color={color} />
                ),
              }}
            />
            <Tab.Screen
              name="Communications"
              component={WorkerCommunicationsScreen}
              options={{
                title: "Comms",
                headerTitle: "Worker Communications",
                tabBarIcon: ({ color, size }) => (
                  <Feather name="message-circle" size={size} color={color} />
                ),
              }}
            />
            <Tab.Screen
              name="Profile"
              component={ProfileScreen}
              options={{
                headerTitle: "Settings",
                tabBarIcon: ({ color, size }) => (
                  <Feather name="settings" size={size} color={color} />
                ),
              }}
            />
          </>
        );

      default:
        return null;
    }
  };

  const isWeb = Platform.OS === "web";

  return (
    <Tab.Navigator
      initialRouteName="Dashboard"
      screenOptions={{
        headerTitleAlign: "center",
        headerTransparent: !isWeb,
        headerBlurEffect: isDark ? "dark" : "light",
        headerTintColor: theme.text,
        headerStyle: {
          backgroundColor: isWeb ? theme.backgroundRoot : undefined,
        },
        tabBarActiveTintColor: theme.tabIconSelected,
        tabBarInactiveTintColor: theme.tabIconDefault,
        tabBarStyle: {
          position: "absolute",
          backgroundColor: Platform.select({
            ios: "transparent",
            android: theme.backgroundRoot,
            web: theme.backgroundRoot,
          }),
          borderTopWidth: 0,
          elevation: 0,
        },
        tabBarBackground: () =>
          Platform.OS === "ios" ? (
            <BlurView
